INSERT INTO `_meta_glossary` VALUES (1,'Chuyền may','Production Line','Một tổ hợp máy may và công nhân sản xuất một loại sản phẩm liên tục'),(2,'Hiệu suất chuyền','Line Efficiency','Tỷ lệ % thời gian sản xuất thực tế so với thời gian lý thuyết theo SAM'),(3,'SAM','Standard Allowed Minutes','Số phút tiêu chuẩn để hoàn thành một sản phẩm'),(4,'DHU','Defects per Hundred Units','Số lỗi trên 100 sản phẩm kiểm tra, chỉ số chất lượng'),(5,'OTD','On-Time Delivery','Tỷ lệ giao hàng đúng hạn theo kế hoạch'),(6,'FOB','Free on Board','Điều kiện giao hàng: bên bán chịu chi phí đến cửa khẩu xuất'),(7,'CMT','Cut-Make-Trim','Phương thức gia công: khách hàng cung cấp vải, TCM cắt may'),(8,'ODM','Original Design Manufacturing','Sản xuất theo thiết kế gốc của nhà sản xuất'),(9,'Loang màu','Color Bleeding/Uneven Dyeing','Lỗi nhuộm: màu không đều hoặc chảy màu'),(10,'Đường may lệch','Seam Deviation','Lỗi may: đường chỉ bị lệch so với chuẩn'),(11,'Vắt sổ','Overlocking','Kỹ thuật may viền mép vải để tránh tưa sổ'),(12,'Năng suất sợi','Yarn Yield','Hiệu suất chuyển hóa nguyên liệu thô thành sợi thành phẩm'),(13,'Phụ liệu','Trim/Accessory','Vật liệu phụ: cúc, dây kéo, nhãn mác...'),(14,'KCN VSIP','Vietnam Singapore Industrial Park','Khu công nghiệp hợp tác Việt Nam - Singapore tại Bình Dương'),(15,'OEE','Overall Equipment Effectiveness','Hiệu quả thiết bị tổng thể = Khả dụng × Hiệu suất × Chất lượng'),(16,'Tỷ lệ sử dụng công suất','Capacity Utilization Rate','% năng lực sản xuất đang được sử dụng so với tổng công suất lắp đặt'),(17,'Biên lợi nhuận gộp','Gross Margin','Tỷ lệ (Doanh thu - Giá vốn) / Doanh thu × 100%'),(18,'Dệt kim','Knitting','Phương pháp tạo vải bằng cách đan các vòng sợi lại với nhau'),(19,'Dệt thoi','Weaving','Phương pháp tạo vải bằng cách đan ngang và dọc'),(20,'Nhuộm','Dyeing','Quá trình nhuộm màu vải hoặc sợi');
/*!40000 ALTER TABLE `_meta_glossary` ENABLE KEYS */;
UNLOCK TABLES;

