INSERT INTO `_meta_kpi` VALUES (1,'OTD Rate','SELECT COUNT(CASE WHEN actual_delivery_date <= planned_delivery_date THEN 1 END)*100.0/COUNT(*) FROM production_orders WHERE status IN (\'Completed\',\'Delayed\')','Tỷ lệ giao hàng đúng hạn = số đơn giao đúng / tổng đơn × 100','OTD tháng X? Line nào OTD thấp nhất? OTD theo nhà máy?'),(2,'DHU Rate','SELECT AVG(dhu_rate) FROM quality_inspections WHERE inspection_date BETWEEN %s AND %s','Defects per Hundred Units = (tổng lỗi / tổng kiểm tra) × 100','DHU sau khi đổi nhà cung cấp? DHU theo chuyền? DHU theo mẫu mã?'),(3,'Line Efficiency','SELECT AVG(line_efficiency_pct) FROM production_orders WHERE factory_id=%s AND MONTH(planned_delivery_date)=%s','Hiệu suất chuyền = (SAM × sản lượng) / (số công nhân × giờ làm) × 100','Chuyền nào hiệu suất cao nhất? So sánh hiệu suất giữa các nhà máy?'),(4,'OEE','SELECT (1 - SUM(downtime_hours)/(COUNT(DISTINCT downtime_date)*8.0)) * line_efficiency_pct/100 AS oee FROM machine_downtime JOIN factory_kpi_monthly USING(factory_id)','Overall Equipment Effectiveness = Availability × Performance × Quality','OEE tháng 10/2025 LINE-TP-03? Máy nào OEE thấp nhất?'),(5,'SAM Achievement','SELECT AVG(sam_achievement_pct) FROM factory_kpi_monthly WHERE factory_id=%s','% đạt SAM = thời gian sản xuất thực tế / SAM chuẩn × 100','Chuyền nào đạt SAM tốt nhất? SAM theo mẫu mã?'),(6,'Fabric Utilization','SELECT AVG(fabric_utilization_pct) FROM factory_kpi_monthly','Hiệu suất sử dụng vải = (vải thực tế sử dụng / vải định mức) × 100','Nhà máy nào lãng phí vải nhất? Xu hướng fabric utilization?'),(7,'Gross Margin','SELECT (SUM(revenue_vnd) - SUM(material_cost_vnd+labor_cost_vnd+overhead_cost_vnd))/SUM(revenue_vnd)*100 FROM sales_orders JOIN cost_breakdown ON sales_orders.production_order_id=cost_breakdown.order_id','Biên lợi nhuận gộp = (Doanh thu - COGS) / Doanh thu × 100','GM Q2 vs Q3 2025? GM theo nhà máy? GM bị ảnh hưởng bởi chi phí NVL?'),(8,'Yarn Yield','SELECT AVG(yarn_yield_pct) FROM cost_breakdown WHERE yarn_yield_pct IS NOT NULL','Hiệu suất sợi = (sản phẩm thực tế) / (nguyên liệu đầu vào) × 100','Yarn yield FAC-SP theo tháng? Trend cải thiện?');
/*!40000 ALTER TABLE `_meta_kpi` ENABLE KEYS */;
UNLOCK TABLES;

